/**
 * MedX modal runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Stack-based modal manager for confirmations, forms, and detail drawers.
 */
const MODAL_SIZES = Object.freeze({
  sm: { maxWidth: "24rem", padding: "p-4" },
  md: { maxWidth: "32rem", padding: "p-6" },
  lg: { maxWidth: "48rem", padding: "p-6" },
  xl: { maxWidth: "64rem", padding: "p-8" },
  full: { maxWidth: "100vw", padding: "p-4" },
});

const MODAL_PRESETS = Object.freeze({
  confirmDelete: {
    title: "Confirm deletion",
    description: "This action cannot be undone. The inventory record will be permanently removed.",
    size: "sm",
    confirmLabel: "Delete",
    cancelLabel: "Cancel",
    destructive: true,
  },
  batchReceive: {
    title: "Receive batch shipment",
    description: "Scan or enter batch details to update warehouse inventory.",
    size: "lg",
    confirmLabel: "Receive",
    cancelLabel: "Cancel",
  },
  coldChainBreach: {
    title: "Cold chain breach detected",
    description: "Temperature exceeded threshold. Review affected lots immediately.",
    size: "md",
    confirmLabel: "View affected lots",
    cancelLabel: "Dismiss",
    destructive: true,
  },
});

const modalStack = [];
const modalListeners = new Set();
let modalIdSeq = 0;

function generateModalId() {
  modalIdSeq += 1;
  return `medx-modal-${modalIdSeq}`;
}

function openModal(config) {
  const preset = config.preset ? MODAL_PRESETS[config.preset] : null;
  const size = config.size ?? preset?.size ?? "md";
  const modal = {
    id: config.id ?? generateModalId(),
    title: config.title ?? preset?.title ?? "Modal",
    description: config.description ?? preset?.description ?? "",
    size,
    sizeStyles: MODAL_SIZES[size] ?? MODAL_SIZES.md,
    confirmLabel: config.confirmLabel ?? preset?.confirmLabel ?? "Confirm",
    cancelLabel: config.cancelLabel ?? preset?.cancelLabel ?? "Cancel",
    destructive: config.destructive ?? preset?.destructive ?? false,
    open: true,
    data: config.data ?? {},
    onConfirm: typeof config.onConfirm === "function" ? config.onConfirm : null,
    onCancel: typeof config.onCancel === "function" ? config.onCancel : null,
    openedAt: Date.now(),
  };
  modalStack.push(modal);
  notifyModalListeners("open", modal);
  return modal;
}

function closeModal(id, reason = "user") {
  const index = modalStack.findIndex((m) => m.id === id);
  if (index === -1) return false;
  const [modal] = modalStack.splice(index, 1);
  modal.open = false;
  modal.closedAt = Date.now();
  modal.closeReason = reason;
  notifyModalListeners("close", modal);
  return true;
}

function closeTopModal(reason = "user") {
  const top = modalStack[modalStack.length - 1];
  if (!top) return false;
  return closeModal(top.id, reason);
}

function getTopModal() {
  return modalStack[modalStack.length - 1] ?? null;
}

function onModalEvent(listener) {
  modalListeners.add(listener);
  return () => modalListeners.delete(listener);
}

function notifyModalListeners(type, modal) {
  for (const listener of modalListeners) {
    try {
      listener({ type, modal, stackDepth: modalStack.length });
    } catch (err) {
      console.warn("[medx:ui:modal] listener error", err.message);
    }
  }
}

async function runMedxModal() {
  console.log("[medx:ui:modal] runtime initialized");
  console.log(`[medx:ui:modal] sizes=${Object.keys(MODAL_SIZES).length} presets=${Object.keys(MODAL_PRESETS).length}`);

  const events = [];
  onModalEvent((e) => events.push(e.type));

  openModal({ preset: "batchReceive", data: { batchId: "BATCH-000042" } });
  openModal({ preset: "coldChainBreach", data: { sensorId: "TEMP-EAST-07", celsius: 9.2 } });

  const top = getTopModal();
  closeTopModal("confirm");
  closeTopModal("cancel");

  console.log(`[medx:ui:modal] stackDepth=${modalStack.length} events=${events.join(",")}`);
  console.log("[medx:ui:modal] lastClosed", top?.title);
  console.log("[medx:ui:modal] bootstrap complete");
}

module.exports = runMedxModal;
